        started_at: session.startedAt,
        completed_at: null,
        final_category_id: null,
        final_confidence: null,
        final_rationale: null,
        final_keywords: [],
        final_features: {},
        ai_routing_used: false,
        status: 'in_progress',
        triggered_by: 'system',
      });

      await repository.createSession(session, 'msg-001');

      expect(mockPrisma.classificationSession.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          gmail_id: 'msg-001',
          pipeline_version: 'v1.0.0',
          started_at: session.startedAt,
          status: 'in_progress',
          triggered_by: 'system',
        }),
      });
    });

    it('should update session on completion', async () => {
      const sessionId = 'session-123';
      const finalCategoryId = 42;
      const confidence = 0.95;
      const rationale = 'High confidence classification';

      mockPrisma.classificationSession.update.mockResolvedValue({
        session_id: 1,
        gmail_id: 'msg-001',
        pipeline_version: 'v1.0.0',
        started_at: new Date(),
        completed_at: new Date(),
        final_category_id: finalCategoryId,
        final_confidence: confidence,
        final_rationale: rationale,
        final_keywords: ['receipt', 'payment'],
        final_features: {},
        ai_routing_used: false,
        status: 'completed',
        triggered_by: 'system',
      });

      await repository.completeSession(sessionId, finalCategoryId, confidence, rationale);

      expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
        where: { session_id: expect.any(Number) },
        data: expect.objectContaining({
          completed_at: expect.any(Date),
          final_category_id: finalCategoryId,
          final_confidence: confidence,
          final_rationale: rationale,
          status: 'completed',
        }),
      });
    });

    it('should handle session not found error gracefully', async () => {
      mockPrisma.classificationSession.update.mockRejectedValue(new Error('Session not found'));

      await expect(repository.completeSession('nonexistent', 1, 0.5, 'test')).rejects.toThrow(
        'Failed to complete session'
      );
    });
  });

  describe('Classification Result Persistence', () => {
    it('should persist classification result with explainability trace', async () => {
      const result: ClassificationResult = {
        id: 'result-123',
        emailId: 'msg-001',
        sessionId: 'session-123',
        primaryCategory: 'financial',
        secondaryCategories: ['receipt'],
        confidence: 0.95,
        explainabilityTrace: {
          sessionId: 'session-123',
          emailId: 'msg-001',
          hardAssertions: [],
          strongIndicators: [],
          ruleScoring: [],
          attributeDetection: [],
