     1→/**
     2→ * Classification Results Persistence Layer (T043) - Prisma Implementation
     3→ *
     4→ * Repository pattern for classification results persistence using Prisma ORM:
     5→ * - Classification session management (create, update, complete)
     6→ * - Classification results with explainability traces
     7→ * - Score breakdown persistence
     8→ * - Attribute context storage
     9→ * - Multi-label classification support
    10→ * - Domain signal resolutions
    11→ * - Transaction-safe batch operations
    12→ *
    13→ * Benefits of Prisma ORM:
    14→ * - Type-safe database queries with auto-generated types
    15→ * - Built-in transaction handling for complex multi-table operations
    16→ * - Automatic JSON serialization/deserialization for explainability data
    17→ * - Connection pooling and query optimization
    18→ * - SQL injection protection via parameterized queries
    19→ */
    20→
    21→import { PrismaClient, Prisma } from '@prisma/client';
    22→import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';
    23→
    24→/**
    25→ * Domain signal resolution data structure
    26→ */
    27→export interface DomainSignalData {
    28→  domain: string;
    29→  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
    30→  matchedCategoryId: number | null;
    31→  confidenceLevel?: string;
    32→  domainType?: string;
    33→}
    34→
    35→/**
    36→ * Classification Repository using Prisma ORM
    37→ *
    38→ * Provides type-safe classification results persistence with automatic transaction
    39→ * handling, connection pooling, and explainability trace integrity.
    40→ */
    41→export class ClassificationRepository {
    42→  private readonly prisma: PrismaClient;
    43→  private readonly ownsPrisma: boolean;
    44→
    45→  /**
    46→   * Initialize classification repository
    47→   *
    48→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    49→   */
    50→  constructor(prisma?: PrismaClient) {
    51→    if (prisma) {
    52→      this.prisma = prisma;
    53→      this.ownsPrisma = false;
    54→    } else {
    55→      this.prisma = new PrismaClient();
    56→      this.ownsPrisma = true;
    57→    }
    58→  }
    59→
    60→  /**
    61→   * Create a new classification session
    62→   *
    63→   * @param session - ClassificationSession object
    64→   * @param gmailId - Gmail message ID being classified
    65→   * @returns Database session ID
    66→   * @throws {Error} If session creation fails
    67→   */
    68→  async createSession(session: ClassificationSession, gmailId: string): Promise<number> {
    69→    try {
    70→      const result = await this.prisma.classificationSession.create({
    71→        data: {
    72→          gmailId: gmailId,
    73→          pipelineVersion: session.configVersion,
    74→          startedAt: session.startedAt,
    75→          status: 'in_progress',
    76→          triggeredBy: 'system',
    77→          aiRoutingUsed: false,
    78→        },
    79→      });
    80→
    81→      return Number(result.sessionId);
    82→    } catch (error) {
    83→      throw new Error(
    84→        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
    85→      );
    86→    }
    87→  }
    88→
    89→  /**
    90→   * Complete a classification session
    91→   *
    92→   * @param sessionId - Session identifier (UUID string)
    93→   * @param finalCategoryId - Final category ID selected
    94→   * @param confidence - Final confidence score
    95→   * @param rationale - Final decision rationale
    96→   * @throws {Error} If session update fails
    97→   */
    98→  async completeSession(
    99→    sessionId: string,
   100→    finalCategoryId: number,
   101→    confidence: number,
   102→    rationale: string
   103→  ): Promise<void> {
   104→    try {
   105→      // Parse sessionId to BigInt for database query
   106→      const dbSessionId = BigInt(sessionId.replace(/\D/g, '').slice(0, 19) || '0');
   107→
   108→      await this.prisma.classificationSession.update({
   109→        where: { sessionId: dbSessionId },
   110→        data: {
   111→          completedAt: new Date(),
   112→          finalCategoryId: finalCategoryId,
   113→          finalConfidence: new Prisma.Decimal(confidence),
   114→          finalRationale: rationale,
   115→          status: 'completed',
   116→        },
   117→      });
   118→    } catch (error) {
   119→      throw new Error(
   120→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   121→      );
   122→    }
   123→  }
   124→
   125→  /**
   126→   * Save complete classification result with explainability trace
   127→   *
   128→   * Uses Prisma transaction to ensure atomicity across multiple tables:
   129→   * - classification_stage (9 pipeline stages)
   130→   * - stage_category_eval (per-category evaluations)
   131→   * - session_categories (multi-label support)
   132→   * - detected_attributes (attribute context)
   133→   * - domain_signal_resolutions (domain signals)
   134→   *
   135→   * @param result - ClassificationResult with explainability trace
   136→   * @param dbSessionId - Database session ID (from createSession)
   137→   * @throws {Error} If save fails (rolls back entire transaction)
   138→   */
   139→  async saveClassificationResult(result: ClassificationResult, dbSessionId: number): Promise<void> {
   140→    try {
   141→      await this.prisma.$transaction(async (tx) => {
   142→        // 1. Create classification stages (9 stages: hard assertions through audit trail)
   143→        const stageData = this.buildStageData(result, BigInt(dbSessionId));
   144→        if (stageData.length > 0) {
   145→          await tx.classificationStage.createMany({ data: stageData });
   146→        }
   147→
   148→        // 2. Create stage category evaluations (score breakdown for each category)
   149→        const categoryEvalData = this.buildCategoryEvalData(result, BigInt(dbSessionId));
   150→        if (categoryEvalData.length > 0) {
   151→          await tx.stageCategoryEval.createMany({ data: categoryEvalData });
   152→        }
   153→
   154→        // 3. Create session categories (multi-label support)
   155→        const sessionCategoryData = this.buildSessionCategoryData(result, BigInt(dbSessionId));
   156→        if (sessionCategoryData.length > 0) {
   157→          await tx.sessionCategory.createMany({ data: sessionCategoryData });
   158→        }
   159→
   160→        // 4. Create detected attributes (attribute context)
   161→        const attributeData = this.buildAttributeData(result.attributeContext, BigInt(dbSessionId));
   162→        if (attributeData.length > 0) {
   163→          await tx.detectedAttribute.createMany({ data: attributeData });
   164→        }
   165→      });
   166→    } catch (error) {
   167→      throw new Error(
   168→        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
   169→      );
   170→    }
   171→  }
   172→
   173→  /**
   174→   * Save attribute context separately
   175→   *
   176→   * @param context - AttributeContext with detected attributes
   177→   * @param dbSessionId - Database session ID
   178→   * @throws {Error} If save fails
   179→   */
   180→  async saveAttributeContext(context: AttributeContext, dbSessionId: number): Promise<void> {
   181→    try {
   182→      const attributeData = this.buildAttributeData(context, BigInt(dbSessionId));
   183→      if (attributeData.length > 0) {
   184→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   185→      }
   186→    } catch (error) {
   187→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   188→    }
   189→  }
   190→
   191→  /**
   192→   * Save domain signal resolutions
   193→   *
   194→   * @param signals - Array of domain signal resolutions
   195→   * @param dbSessionId - Database session ID
   196→   * @throws {Error} If save fails
   197→   */
   198→  async saveDomainSignals(signals: DomainSignalData[], dbSessionId: number): Promise<void> {
   199→    if (signals.length === 0) {
   200→      return;
   201→    }
   202→
   203→    try {
   204→      await this.prisma.domainSignalResolution.createMany({
   205→        data: signals.map((signal) => ({
   206→          sessionId: BigInt(dbSessionId),
   207→          domain: signal.domain,
   208→          signalType: signal.signalType,
   209→          matchedCategoryId: signal.matchedCategoryId,
   210→          confidenceLevel: signal.confidenceLevel || null,
   211→          domainType: signal.domainType || null,
   212→          createdAt: new Date(),
   213→        })),
   214→      });
   215→    } catch (error) {
   216→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   217→    }
   218→  }
   219→
   220→  /**
   221→   * Batch save multiple classification results
   222→   *
   223→   * @param results - Array of ClassificationResult objects
   224→   * @param dbSessionId - Database session ID
   225→   * @throws {Error} If batch save fails
   226→   */
   227→  async batchSaveResults(results: ClassificationResult[], dbSessionId: number): Promise<void> {
   228→    if (results.length === 0) {
   229→      return;
   230→    }
   231→
   232→    try {
   233→      // Save each result sequentially within a transaction
   234→      for (const result of results) {
   235→        await this.saveClassificationResult(result, dbSessionId);
   236→      }
   237→    } catch (error) {
   238→      throw new Error(
   239→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   240→      );
   241→    }
   242→  }
   243→
   244→  /**
   245→   * Build classification stage data from explainability trace
   246→   */
   247→  private buildStageData(
   248→    result: ClassificationResult,
   249→    sessionId: bigint
   250→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   251→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   252→    const trace = result.explainabilityTrace;
   253→
   254→    // Map pipeline stages to database records
   255→    const stageMapping = [
   256→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   257→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   258→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   259→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   260→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   261→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
   262→      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
   263→      { order: 8, type: 'ai_routing', data: trace.aiRouting },
   264→      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
   265→    ];
   266→
   267→    for (const stage of stageMapping) {
   268→      stages.push({
   269→        sessionId: sessionId,
   270→        stageOrder: stage.order,
   271→        stageType: stage.type,
   272→        startedAt: new Date(),
   273→        endedAt: new Date(),
   274→        features: stage.data as Prisma.InputJsonValue,
   275→        keywords: [],
   276→        passedToNext: true,
   277→      });
   278→    }
   279→
   280→    return stages;
   281→  }
   282→
   283→  /**
   284→   * Build stage category evaluation data from score breakdown
   285→   */
   286→  private buildCategoryEvalData(
   287→    result: ClassificationResult,
   288→    sessionId: bigint
   289→  ): Array<Prisma.StageCategoryEvalCreateManyInput> {
   290→    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
   291→    const scoreBreakdown = result.scoreBreakdown;
   292→
   293→    // Extract category scores and create evaluations
   294→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   295→      evaluations.push({
   296→        stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   297→        categoryId: this.getCategoryIdFromCode(category),
   298→        decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
   299→        score: scores as unknown as Prisma.InputJsonValue,
   300→        confidence: new Prisma.Decimal(scores.finalScore || 0),
   301→        scoringComponents: scores as unknown as Prisma.InputJsonValue,
   302→        keywords: [],
   303→        createdAt: new Date(),
   304→      });
   305→    }
   306→
   307→    return evaluations;
   308→  }
   309→
   310→  /**
   311→   * Build session category data (multi-label support)
   312→   */
   313→  private buildSessionCategoryData(
   314→    result: ClassificationResult,
   315→    sessionId: bigint
   316→  ): Array<Prisma.SessionCategoryCreateManyInput> {
   317→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   318→
   319→    for (const label of result.selectedLabels) {
   320→      categories.push({
   321→        sessionId: sessionId,
   322→        categoryId: this.getCategoryIdFromCode(label.category),
   323→        subtypeId: label.subtype ? this.getCategoryIdFromCode(label.subtype) : null,
   324→        isPrimary: label.isPrimary,
   325→        confidence: new Prisma.Decimal(label.confidence),
   326→        categoryScore: new Prisma.Decimal(label.score),
   327→        hardAssertion: false, // TODO: Extract from explainability trace
   328→        aiClassified: result.aiRoutingUsed,
   329→        scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   330→        labelOrder: label.labelOrder,
   331→        createdAt: new Date(),
   332→      });
   333→    }
   334→
   335→    return categories;
   336→  }
   337→
   338→  /**
   339→   * Build detected attribute data from attribute context
   340→   */
   341→  private buildAttributeData(
   342→    context: AttributeContext,
   343→    sessionId: bigint
   344→  ): Array<Prisma.DetectedAttributeCreateManyInput> {
   345→    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];
   346→
   347→    // Add urgency attribute
   348→    attributes.push({
   349→      sessionId: sessionId,
   350→      attributeName: 'urgency',
   351→      attributeValue: context.urgency,
   352→      detectionMethod: 'rule',
   353→      detectionEvidence: 'Urgency level detection',
   354→      influenceRole: 'FILTER',
   355→      categoriesInfluenced: [],
   356→      totalBonusApplied: new Prisma.Decimal(0),
   357→      createdAt: new Date(),
   358→    });
   359→
   360→    // Add domain attributes
   361→    for (const domain of context.domains) {
   362→      attributes.push({
   363→        sessionId: sessionId,
   364→        attributeName: `domain:${domain}`,
   365→        attributeValue: domain,
   366→        detectionMethod: 'domain_lookup',
   367→        detectionEvidence: `Domain ${domain} detected`,
   368→        influenceRole: 'CORE',
   369→        categoriesInfluenced: [],
   370→        totalBonusApplied: new Prisma.Decimal(0),
   371→        createdAt: new Date(),
   372→      });
   373→    }
   374→
   375→    // Add structural pattern attributes
   376→    for (const pattern of context.structuralPatterns) {
   377→      attributes.push({
   378→        sessionId: sessionId,
   379→        attributeName: `pattern:${pattern}`,
   380→        attributeValue: pattern,
   381→        detectionMethod: 'regex',
   382→        detectionEvidence: `Pattern ${pattern} matched`,
   383→        influenceRole: 'SECONDARY_BOOST',
   384→        categoriesInfluenced: [],
   385→        totalBonusApplied: new Prisma.Decimal(0),
   386→        createdAt: new Date(),
   387→      });
   388→    }
   389→
   390→    return attributes;
   391→  }
   392→
   393→  /**
   394→   * Get category ID from category code
   395→   *
   396→   * TODO: Implement proper category lookup (load from database or config)
   397→   * For now, using simple hash function to generate consistent IDs
   398→   */
   399→  private getCategoryIdFromCode(code: string): number {
   400→    // Simple hash function for MVP - replace with actual database lookup
   401→    let hash = 0;
   402→    for (let i = 0; i < code.length; i++) {
   403→      hash = (hash << 5) - hash + code.charCodeAt(i);
   404→      hash = hash & hash; // Convert to 32-bit integer
   405→    }
   406→    return Math.abs(hash) % 1000; // Return ID in range 0-999
   407→  }
   408→
   409→  /**
   410→   * Close the Prisma client connection
   411→   *
   412→   * Only closes if using default Prisma instance (not externally provided).
   413→   */
   414→  async close(): Promise<void> {
   415→    if (this.ownsPrisma) {
   416→      await this.prisma.$disconnect();
   417→    }
   418→  }
   419→}
