/**
 * Classification Results Persistence Layer (T043) - Prisma Implementation
 *
 * Repository pattern for classification results persistence using Prisma ORM:
 * - Classification session management (create, update, complete)
 * - Classification results with explainability traces
 * - Score breakdown persistence
 * - Attribute context storage
 * - Multi-label classification support
 * - Domain signal resolutions
 * - Transaction-safe batch operations
 *
 * Benefits of Prisma ORM:
 * - Type-safe database queries with auto-generated types
 * - Built-in transaction handling for complex multi-table operations
 * - Automatic JSON serialization/deserialization for explainability data
 * - Connection pooling and query optimization
 * - SQL injection protection via parameterized queries
 */

import { PrismaClient, Prisma } from '@prisma/client';
import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';

/**
 * Domain signal resolution data structure
 */
export interface DomainSignalData {
  domain: string;
  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
  matchedCategoryId: number | null;
  confidenceLevel?: string;
  domainType?: string;
}

/**
 * Classification Repository using Prisma ORM
 *
 * Provides type-safe classification results persistence with automatic transaction
 * handling, connection pooling, and explainability trace integrity.
 */
export class ClassificationRepository {
  private readonly prisma: PrismaClient;
  private readonly ownsPrisma: boolean;

  /**
   * Initialize classification repository
   *
   * @param prisma - Optional Prisma client instance (creates default if not provided)
   */
  constructor(prisma?: PrismaClient) {
    if (prisma) {
      this.prisma = prisma;
      this.ownsPrisma = false;
    } else {
      this.prisma = new PrismaClient();
      this.ownsPrisma = true;
    }
  }

  /**
   * Create a new classification session
   *
   * @param session - ClassificationSession object
   * @param gmailId - Gmail message ID being classified
   * @returns Database session ID
   * @throws {Error} If session creation fails
   */
  async createSession(session: ClassificationSession, gmailId: string): Promise<number> {
    try {
      const result = await this.prisma.classificationSession.create({
        data: {
          gmailId: gmailId,
          pipelineVersion: session.configVersion,
          startedAt: session.startedAt,
          status: 'in_progress',
          triggeredBy: 'system',
          aiRoutingUsed: false,
        },
      });

      return Number(result.sessionId);
    } catch (error) {
      throw new Error(
        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Complete a classification session
   *
   * @param sessionId - Session identifier (UUID string)
   * @param finalCategoryId - Final category ID selected
   * @param confidence - Final confidence score
   * @param rationale - Final decision rationale
   * @throws {Error} If session update fails
   */
  async completeSession(
    sessionId: string,
    finalCategoryId: number,
    confidence: number,
    rationale: string
  ): Promise<void> {
    try {
      // Parse sessionId to BigInt for database query
      const dbSessionId = BigInt(sessionId.replace(/\D/g, '').slice(0, 19) || '0');

      await this.prisma.classificationSession.update({
        where: { sessionId: dbSessionId },
        data: {
          completedAt: new Date(),
          finalCategoryId: finalCategoryId,
          finalConfidence: new Prisma.Decimal(confidence),
          finalRationale: rationale,
          status: 'completed',
        },
      });
    } catch (error) {
      throw new Error(
        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Save complete classification result with explainability trace
   *
   * Uses Prisma transaction to ensure atomicity across multiple tables:
   * - classification_stage (9 pipeline stages)
   * - stage_category_eval (per-category evaluations)
   * - session_categories (multi-label support)
   * - detected_attributes (attribute context)
   * - domain_signal_resolutions (domain signals)
   *
   * @param result - ClassificationResult with explainability trace
   * @param dbSessionId - Database session ID (from createSession)
   * @throws {Error} If save fails (rolls back entire transaction)
   */
  async saveClassificationResult(result: ClassificationResult, dbSessionId: number): Promise<void> {
    try {
      await this.prisma.$transaction(async (tx) => {
        // 1. Create classification stages (9 stages: hard assertions through audit trail)
        const stageData = this.buildStageData(result, BigInt(dbSessionId));
        if (stageData.length > 0) {
          await tx.classificationStage.createMany({ data: stageData });
        }

        // 2. Create stage category evaluations (score breakdown for each category)
        const categoryEvalData = this.buildCategoryEvalData(result, BigInt(dbSessionId));
        if (categoryEvalData.length > 0) {
          await tx.stageCategoryEval.createMany({ data: categoryEvalData });
        }

        // 3. Create session categories (multi-label support)
        const sessionCategoryData = this.buildSessionCategoryData(result, BigInt(dbSessionId));
        if (sessionCategoryData.length > 0) {
          await tx.sessionCategory.createMany({ data: sessionCategoryData });
        }

        // 4. Create detected attributes (attribute context)
        const attributeData = this.buildAttributeData(result.attributeContext, BigInt(dbSessionId));
        if (attributeData.length > 0) {
          await tx.detectedAttribute.createMany({ data: attributeData });
        }
      });
    } catch (error) {
      throw new Error(
        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Save attribute context separately
   *
   * @param context - AttributeContext with detected attributes
   * @param dbSessionId - Database session ID
   * @throws {Error} If save fails
   */
  async saveAttributeContext(context: AttributeContext, dbSessionId: number): Promise<void> {
    try {
      const attributeData = this.buildAttributeData(context, BigInt(dbSessionId));
      if (attributeData.length > 0) {
        await this.prisma.detectedAttribute.createMany({ data: attributeData });
      }
    } catch (error) {
      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Save domain signal resolutions
   *
   * @param signals - Array of domain signal resolutions
   * @param dbSessionId - Database session ID
   * @throws {Error} If save fails
   */
  async saveDomainSignals(signals: DomainSignalData[], dbSessionId: number): Promise<void> {
    if (signals.length === 0) {
      return;
    }

    try {
      await this.prisma.domainSignalResolution.createMany({
        data: signals.map((signal) => ({
          sessionId: BigInt(dbSessionId),
          domain: signal.domain,
          signalType: signal.signalType,
          matchedCategoryId: signal.matchedCategoryId,
          confidenceLevel: signal.confidenceLevel || null,
          domainType: signal.domainType || null,
          createdAt: new Date(),
        })),
      });
    } catch (error) {
      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Batch save multiple classification results
   *
   * @param results - Array of ClassificationResult objects
   * @param dbSessionId - Database session ID
   * @throws {Error} If batch save fails
   */
  async batchSaveResults(results: ClassificationResult[], dbSessionId: number): Promise<void> {
    if (results.length === 0) {
      return;
    }

    try {
      // Save each result sequentially within a transaction
      for (const result of results) {
        await this.saveClassificationResult(result, dbSessionId);
      }
    } catch (error) {
      throw new Error(
        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Build classification stage data from explainability trace
   */
  private buildStageData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.ClassificationStageCreateManyInput> {
    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
    const trace = result.explainabilityTrace;

    // Map pipeline stages to database records
    const stageMapping = [
      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
      { order: 6, type: 'disambiguation', data: trace.disambiguation },
      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
      { order: 8, type: 'ai_routing', data: trace.aiRouting },
      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
    ];

    for (const stage of stageMapping) {
      stages.push({
        sessionId: sessionId,
        stageOrder: stage.order,
        stageType: stage.type,
        startedAt: new Date(),
        endedAt: new Date(),
        features: stage.data as Prisma.InputJsonValue,
        keywords: [],
        passedToNext: true,
      });
    }

    return stages;
  }

  /**
   * Build stage category evaluation data from score breakdown
   */
  private buildCategoryEvalData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.StageCategoryEvalCreateManyInput> {
    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
    const scoreBreakdown = result.scoreBreakdown;

    // Extract category scores and create evaluations
    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
      evaluations.push({
        stageId: sessionId, // Simplified: using session_id as stage_id for MVP
        categoryId: this.getCategoryIdFromCode(category),
        decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
        score: scores as unknown as Prisma.InputJsonValue,
        confidence: new Prisma.Decimal(scores.finalScore || 0),
        scoringComponents: scores as unknown as Prisma.InputJsonValue,
        keywords: [],
        createdAt: new Date(),
      });
    }

    return evaluations;
  }

  /**
   * Build session category data (multi-label support)
   */
  private buildSessionCategoryData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.SessionCategoryCreateManyInput> {
    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];

    for (const label of result.selectedLabels) {
      categories.push({
        sessionId: sessionId,
        categoryId: this.getCategoryIdFromCode(label.category),
        subtypeId: label.subtype ? this.getCategoryIdFromCode(label.subtype) : null,
        isPrimary: label.isPrimary,
        confidence: new Prisma.Decimal(label.confidence),
        categoryScore: new Prisma.Decimal(label.score),
        hardAssertion: false, // TODO: Extract from explainability trace
        aiClassified: result.aiRoutingUsed,
        scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
        labelOrder: label.labelOrder,
        createdAt: new Date(),
      });
    }

    return categories;
  }

  /**
   * Build detected attribute data from attribute context
   */
  private buildAttributeData(
    context: AttributeContext,
    sessionId: bigint
  ): Array<Prisma.DetectedAttributeCreateManyInput> {
    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];

    // Add urgency attribute
    attributes.push({
      sessionId: sessionId,
      attributeName: 'urgency',
      attributeValue: context.urgency,
      detectionMethod: 'rule',
      detectionEvidence: 'Urgency level detection',
      influenceRole: 'FILTER',
      categoriesInfluenced: [],
      totalBonusApplied: new Prisma.Decimal(0),
      createdAt: new Date(),
    });

    // Add domain attributes
    for (const domain of context.domains) {
      attributes.push({
        sessionId: sessionId,
        attributeName: `domain:${domain}`,
        attributeValue: domain,
        detectionMethod: 'domain_lookup',
        detectionEvidence: `Domain ${domain} detected`,
        influenceRole: 'CORE',
        categoriesInfluenced: [],
        totalBonusApplied: new Prisma.Decimal(0),
        createdAt: new Date(),
      });
    }

    // Add structural pattern attributes
    for (const pattern of context.structuralPatterns) {
      attributes.push({
        sessionId: sessionId,
        attributeName: `pattern:${pattern}`,
        attributeValue: pattern,
        detectionMethod: 'regex',
        detectionEvidence: `Pattern ${pattern} matched`,
        influenceRole: 'SECONDARY_BOOST',
        categoriesInfluenced: [],
        totalBonusApplied: new Prisma.Decimal(0),
        createdAt: new Date(),
      });
    }

    return attributes;
  }

  /**
   * Get category ID from category code
   *
   * TODO: Implement proper category lookup (load from database or config)
   * For now, using simple hash function to generate consistent IDs
   */
  private getCategoryIdFromCode(code: string): number {
    // Simple hash function for MVP - replace with actual database lookup
    let hash = 0;
    for (let i = 0; i < code.length; i++) {
      hash = (hash << 5) - hash + code.charCodeAt(i);
      hash = hash & hash; // Convert to 32-bit integer
    }
    return Math.abs(hash) % 1000; // Return ID in range 0-999
  }

  /**
   * Close the Prisma client connection
   *
   * Only closes if using default Prisma instance (not externally provided).
   */
  async close(): Promise<void> {
    if (this.ownsPrisma) {
      await this.prisma.$disconnect();
    }
  }
}

/**
 * Unit tests for ClassificationRepository (T043 - TDD Approach)
 *
 * Tests classification results persistence with explainability trace storage,
 * score breakdown persistence, and audit trail integrity.
 *
 * Test Strategy:
 * - Mock Prisma client for unit testing
 * - Test session lifecycle (create, update, complete)
 * - Test classification result persistence with nested data
 * - Test multi-label support
 * - Test attribute context and domain signal persistence
 * - Test error handling and transaction rollback
 */

import { ClassificationRepository } from '../../src/persistence/classification-repository';
import { Prisma, PrismaClient } from '@prisma/client';
import { ClassificationResult, ClassificationSession } from '@gmail-automation/classification-engine';

// Mock Prisma Client
jest.mock('@prisma/client', () => {
  const mockPrismaClient = {
    classificationSession: {
      create: jest.fn(),
      update: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
    },
    classificationStage: {
      create: jest.fn(),
      createMany: jest.fn(),
    },
    stageCategoryEval: {
      createMany: jest.fn(),
    },
    sessionCategory: {
      createMany: jest.fn(),
    },
    detectedAttribute: {
      createMany: jest.fn(),
    },
    domainSignalResolution: {
      createMany: jest.fn(),
    },
    $transaction: jest.fn((callback) => callback(mockPrismaClient)),
    $disconnect: jest.fn(),
  };

  // Mock Prisma Decimal class
  class MockDecimal {
    value: number;
    constructor(value: number | string) {
      this.value = typeof value === 'string' ? parseFloat(value) : value;
    }
    toString() {
      return this.value.toString();
    }
    toNumber() {
      return this.value;
    }
  }

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      Decimal: MockDecimal,
    },
  };
});

describe('ClassificationRepository', () => {
  let repository: ClassificationRepository;
  let mockPrisma: jest.Mocked<PrismaClient>;

  beforeEach(() => {
    // Reset all mocks before each test
    jest.clearAllMocks();

    // Create repository with mocked Prisma
    repository = new ClassificationRepository();
    mockPrisma = (repository as any).prisma;
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('Session Management', () => {
    it('should create a new classification session', async () => {
      const session: ClassificationSession = {
        id: 'session-123',
        startedAt: new Date('2025-01-01T10:00:00Z'),
        emailCount: 10,
        successCount: 0,
        errorCount: 0,
        processingMode: 'parallel',
        batchSize: 10,
        performanceMetrics: {
          totalDurationMs: 0,
          avgEmailDurationMs: 0,
          parallelStagesCount: 0,
          databaseBatchOps: 0,
        },
        configVersion: 'v1.0.0',
        configSnapshot: { version: 1 },
        errors: [],
        warnings: [],
      };

      mockPrisma.classificationSession.create.mockResolvedValue({
        session_id: 1,
        gmail_id: 'msg-001',
        pipeline_version: 'v1.0.0',
        started_at: session.startedAt,
        completed_at: null,
        final_category_id: null,
        final_confidence: null,
        final_rationale: null,
        final_keywords: [],
        final_features: {},
        ai_routing_used: false,
        status: 'in_progress',
        triggered_by: 'system',
      });

      await repository.createSession(session, 'msg-001');

      expect(mockPrisma.classificationSession.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          gmail_id: 'msg-001',
          pipeline_version: 'v1.0.0',
          started_at: session.startedAt,
          status: 'in_progress',
          triggered_by: 'system',
        }),
      });
    });

    it('should update session on completion', async () => {
      const sessionId = 'session-123';
      const finalCategoryId = 42;
      const confidence = 0.95;
      const rationale = 'High confidence classification';

      mockPrisma.classificationSession.update.mockResolvedValue({
        session_id: 1,
        gmail_id: 'msg-001',
        pipeline_version: 'v1.0.0',
        started_at: new Date(),
        completed_at: new Date(),
        final_category_id: finalCategoryId,
        final_confidence: confidence,
        final_rationale: rationale,
        final_keywords: ['receipt', 'payment'],
        final_features: {},
        ai_routing_used: false,
        status: 'completed',
        triggered_by: 'system',
      });

      await repository.completeSession(sessionId, finalCategoryId, confidence, rationale);

      expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
        where: { session_id: expect.any(Number) },
        data: expect.objectContaining({
          completed_at: expect.any(Date),
          final_category_id: finalCategoryId,
          final_confidence: confidence,
          final_rationale: rationale,
          status: 'completed',
        }),
      });
    });

    it('should handle session not found error gracefully', async () => {
      mockPrisma.classificationSession.update.mockRejectedValue(new Error('Session not found'));

      await expect(repository.completeSession('nonexistent', 1, 0.5, 'test')).rejects.toThrow(
        'Failed to complete session'
      );
    });
  });

  describe('Classification Result Persistence', () => {
    it('should persist classification result with explainability trace', async () => {
      const result: ClassificationResult = {
        id: 'result-123',
        emailId: 'msg-001',
        sessionId: 'session-123',
        primaryCategory: 'financial',
        secondaryCategories: ['receipt'],
        confidence: 0.95,
        explainabilityTrace: {
          sessionId: 'session-123',
          emailId: 'msg-001',
          hardAssertions: [],
          strongIndicators: [],
          ruleScoring: [],
          attributeDetection: [],
          attributeInfluence: [],
          disambiguation: [],
          multiLabelSelection: [],
          aiRouting: undefined,
          stageTimings: { hardAssertions: 10, strongIndicators: 15 },
          parallelExecutionMap: {},
          configurationRefs: {},
          finalDecisionReason: 'High confidence from domain matching',
          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: 'msg-001',
          categoryScores: {
            financial: {
              baseScore: 0.5,
              hardAssertionBonus: 0.3,
              strongIndicatorScore: 0.1,
              ruleScore: 0.05,
              attributeInfluenceScore: 0.0,
              finalScore: 0.95,
              parallelComputedComponents: [],
              computationDurationMs: 50,
              cacheHits: [],
            },
          },
          stageContributions: {},
          disambiguationApplied: [],
        },
        attributeContext: {
          emailId: 'msg-001',
          urgency: 'low',
          domains: ['chase.com'],
          structuralPatterns: [],
          temporalSignals: [],
          detectionMetadata: {},
          influenceApplications: [],
        },
        processedAt: new Date('2025-01-01T10:05:00Z'),
        processingDurationMs: 5000,
        aiRoutingUsed: false,
        batchPosition: 1,
        parallelStageResults: [],
        selectedLabels: [
          {
            category: 'financial',
            subtype: 'receipt',
            confidence: 0.95,
            score: 0.95,
            isPrimary: true,
            labelOrder: 1,
            selectionRationale: 'Domain match + subject keywords',
          },
        ],
        candidateScores: {
          financial: { score: 0.95, confidence: 0.95, decision: 'selected' },
        },
        selectionSummary: {
          totalLabels: 1,
          primaryCategory: 'financial',
          confidenceRange: [0.95, 0.95],
          selectionMethod: 'rule-based',
          needsAi: false,
        },
        needsAiClassification: false,
      };

      // Mock transaction to succeed
      mockPrisma.$transaction.mockImplementation(async (callback) => {
        return callback(mockPrisma);
      });

      mockPrisma.classificationStage.createMany.mockResolvedValue({ count: 9 });
      mockPrisma.stageCategoryEval.createMany.mockResolvedValue({ count: 6 });
      (mockPrisma as any).sessionCategory.createMany.mockResolvedValue({ count: 1 });
      (mockPrisma as any).detectedAttribute.createMany.mockResolvedValue({ count: 2 });

      await repository.saveClassificationResult(result, 1);

      // Verify transaction was used
      expect(mockPrisma.$transaction).toHaveBeenCalled();

      // Verify classification stages were created
      expect(mockPrisma.classificationStage.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            session_id: 1,
            stage_type: expect.any(String),
            stage_order: expect.any(Number),
          }),
        ]),
      });

      // Verify session categories were created
      expect((mockPrisma as any).sessionCategory.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            sessionId: BigInt(1),
            isPrimary: true,
          }),
        ]),
      });
    });

    it('should handle multi-label classification results', async () => {
      const result: ClassificationResult = {
        id: 'result-456',
        emailId: 'msg-002',
        sessionId: 'session-456',
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85,
        explainabilityTrace: {
          sessionId: 'session-456',
          emailId: 'msg-002',
          hardAssertions: [],
          strongIndicators: [],
          ruleScoring: [],
          attributeDetection: [],
          attributeInfluence: [],
          disambiguation: [],
          multiLabelSelection: [],
          stageTimings: {},
          parallelExecutionMap: {},
          configurationRefs: {},
          finalDecisionReason: 'Multi-label classification',
          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: 'msg-002',
          categoryScores: {},
          stageContributions: {},
          disambiguationApplied: [],
        },
        attributeContext: {
          emailId: 'msg-002',
          urgency: 'high',
          domains: [],
          structuralPatterns: [],
          temporalSignals: [],
          detectionMetadata: {},
          influenceApplications: [],
        },
        processedAt: new Date(),
        processingDurationMs: 3000,
        aiRoutingUsed: false,
        batchPosition: 2,
        parallelStageResults: [],
        selectedLabels: [
          {
            category: 'financial',
            subtype: 'bill',
            confidence: 0.85,
            score: 0.85,
            isPrimary: true,
            labelOrder: 1,
            selectionRationale: 'Primary category',
          },
          {
            category: 'actionable',
            subtype: null,
            confidence: 0.75,
            score: 0.75,
            isPrimary: false,
            labelOrder: 2,
            selectionRationale: 'Secondary category',
          },
        ],
        candidateScores: {},
        selectionSummary: {
          totalLabels: 2,
          primaryCategory: 'financial',
          confidenceRange: [0.75, 0.85],
          selectionMethod: 'rule-based',
          needsAi: false,
        },
        needsAiClassification: false,
      };

      mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));
      mockPrisma.classificationStage.createMany.mockResolvedValue({ count: 9 });
      mockPrisma.sessionCategories.createMany.mockResolvedValue({ count: 2 });

      await repository.saveClassificationResult(result, 1);

      // Verify both primary and secondary labels were saved
      expect(mockPrisma.sessionCategories.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({ is_primary: true, label_order: 1 }),
          expect.objectContaining({ is_primary: false, label_order: 2 }),
        ]),
      });
    });

    it('should rollback transaction on error', async () => {
      const result: Partial<ClassificationResult> = {
        id: 'result-error',
        emailId: 'msg-error',
        sessionId: 'session-error',
        primaryCategory: 'test',
        secondaryCategories: [],
        confidence: 0.5,
      };

      // Mock transaction to simulate error
      mockPrisma.$transaction.mockRejectedValue(new Error('Database constraint violation'));

      await expect(repository.saveClassificationResult(result as ClassificationResult, 1)).rejects.toThrow(
        'Failed to save classification result'
      );

      // Verify transaction was attempted
      expect(mockPrisma.$transaction).toHaveBeenCalled();
    });
  });

  describe('Attribute Context Persistence', () => {
    it('should persist detected attributes with influence tracking', async () => {
      const attributeContext = {
        emailId: 'msg-003',
        urgency: 'high' as const,
        domains: ['amazon.com'],
        structuralPatterns: ['order_confirmation'],
        temporalSignals: [],
        detectionMetadata: {
          urgency: {
            detectedAt: new Date(),
            confidence: 0.9,
            detectionMethod: 'rule' as const,
            parallelProcessed: false,
            dependencies: [],
          },
        },
        influenceApplications: [
          {
            targetCategory: 'ecommerce',
            attributeUsed: 'domain:amazon.com',
            roleType: 'CORE' as const,
            scoreImpact: 0.5,
            applicationReason: 'Domain hard assertion',
          },
        ],
      };

      mockPrisma.detectedAttributes.createMany.mockResolvedValue({ count: 2 });

      await repository.saveAttributeContext(attributeContext, 1);

      expect(mockPrisma.detectedAttributes.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            session_id: 1,
            attribute_name: expect.any(String),
            detection_method: expect.any(String),
            influence_role: expect.any(String),
          }),
        ]),
      });
    });

    it('should handle empty attribute context gracefully', async () => {
      const emptyContext = {
        emailId: 'msg-004',
        urgency: 'low' as const,
        domains: [],
        structuralPatterns: [],
        temporalSignals: [],
        detectionMetadata: {},
        influenceApplications: [],
      };

      mockPrisma.detectedAttributes.createMany.mockResolvedValue({ count: 0 });

      await repository.saveAttributeContext(emptyContext, 1);

      // Should still attempt to save (even if empty)
      expect(mockPrisma.detectedAttributes.createMany).toHaveBeenCalled();
    });
  });

  describe('Domain Signal Resolutions', () => {
    it('should persist domain signal resolutions', async () => {
      const domainSignals = [
        {
          domain: 'chase.com',
          signalType: 'hard_assertion' as const,
          matchedCategoryId: 10,
          confidenceLevel: 'high',
          domainType: 'financial',
        },
        {
          domain: 'newsletter.example.com',
          signalType: 'strong_indicator' as const,
          matchedCategoryId: 20,
          confidenceLevel: 'medium',
          domainType: 'newsletter',
        },
      ];

      mockPrisma.domainSignalResolutions.createMany.mockResolvedValue({ count: 2 });

      await repository.saveDomainSignals(domainSignals, 1);

      expect(mockPrisma.domainSignalResolutions.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            session_id: 1,
            domain: 'chase.com',
            signal_type: 'hard_assertion',
            matched_category_id: 10,
          }),
          expect.objectContaining({
            session_id: 1,
            domain: 'newsletter.example.com',
            signal_type: 'strong_indicator',
            matched_category_id: 20,
          }),
        ]),
      });
    });
  });

  describe('Batch Operations', () => {
    it('should support batch classification result persistence', async () => {
      const results: ClassificationResult[] = [
        {
          id: 'result-batch-1',
          emailId: 'msg-batch-1',
          sessionId: 'session-batch',
          primaryCategory: 'financial',
          secondaryCategories: [],
          confidence: 0.9,
          processedAt: new Date(),
          processingDurationMs: 1000,
          aiRoutingUsed: false,
          batchPosition: 1,
          parallelStageResults: [],
          selectedLabels: [],
          candidateScores: {},
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'financial',
            confidenceRange: [0.9, 0.9],
            selectionMethod: 'rule-based',
            needsAi: false,
          },
          needsAiClassification: false,
          explainabilityTrace: {} as any,
          scoreBreakdown: {} as any,
          attributeContext: {} as any,
        },
        {
          id: 'result-batch-2',
          emailId: 'msg-batch-2',
          sessionId: 'session-batch',
          primaryCategory: 'newsletter',
          secondaryCategories: [],
          confidence: 0.85,
          processedAt: new Date(),
          processingDurationMs: 1200,
          aiRoutingUsed: false,
          batchPosition: 2,
          parallelStageResults: [],
          selectedLabels: [],
          candidateScores: {},
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'newsletter',
            confidenceRange: [0.85, 0.85],
            selectionMethod: 'rule-based',
            needsAi: false,
          },
          needsAiClassification: false,
          explainabilityTrace: {} as any,
          scoreBreakdown: {} as any,
          attributeContext: {} as any,
        },
      ];

      mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));
      mockPrisma.classificationStage.createMany.mockResolvedValue({ count: 18 });
      mockPrisma.sessionCategories.createMany.mockResolvedValue({ count: 2 });

      await repository.batchSaveResults(results, 1);

      // Should use transaction for batch save
      expect(mockPrisma.$transaction).toHaveBeenCalled();

      // Should save all results
      expect(mockPrisma.sessionCategories.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({ session_id: 1 }),
          expect.objectContaining({ session_id: 1 }),
        ]),
      });
    });

    it('should handle partial batch failures gracefully', async () => {
      const results: ClassificationResult[] = [
        {
          id: 'result-fail-1',
          emailId: 'msg-fail-1',
          sessionId: 'session-fail',
          primaryCategory: 'test',
          secondaryCategories: [],
          confidence: 0.5,
          processedAt: new Date(),
          processingDurationMs: 500,
          aiRoutingUsed: false,
          batchPosition: 1,
          parallelStageResults: [],
          selectedLabels: [],
          candidateScores: {},
          selectionSummary: {
            totalLabels: 0,
            primaryCategory: null,
            confidenceRange: [0, 0],
            selectionMethod: 'rule-based',
            needsAi: false,
          },
          needsAiClassification: false,
          explainabilityTrace: {} as any,
          scoreBreakdown: {} as any,
          attributeContext: {} as any,
        },
      ];

      mockPrisma.$transaction.mockRejectedValue(new Error('Constraint violation'));

      await expect(repository.batchSaveResults(results, 1)).rejects.toThrow(
        'Failed to batch save classification results'
      );
    });
  });

  describe('Constructor and Cleanup', () => {
    it('should create repository with default Prisma client', () => {
      const repo = new ClassificationRepository();
      expect(repo).toBeInstanceOf(ClassificationRepository);
    });

    it('should create repository with provided Prisma client', () => {
      const externalPrisma = new PrismaClient();
      const repo = new ClassificationRepository(externalPrisma);
      expect(repo).toBeInstanceOf(ClassificationRepository);
    });

    it('should close repository and disconnect Prisma', async () => {
      const repo = new ClassificationRepository();
      await repo.close();

      expect(mockPrisma.$disconnect).toHaveBeenCalled();
    });

    it('should not disconnect externally provided Prisma client', async () => {
      const externalPrisma = new PrismaClient();
      const repo = new ClassificationRepository(externalPrisma);
      await repo.close();

      // Should not disconnect external client
      expect(mockPrisma.$disconnect).not.toHaveBeenCalled();
    });
  });
});

